CREATE TABLE musteri_sikayeti (
  id           uuid PRIMARY KEY,
  konu         text NOT NULL,
  aciklama     text NOT NULL,
  oncelik      text NOT NULL DEFAULT 'orta',
  atanan_id    uuid REFERENCES users(id),   -- Foreign Key
  musteri_id   uuid NOT NULL REFERENCES customers(id),
  created_at   timestamptz NOT NULL DEFAULT now(),
  updated_at   timestamptz NOT NULL DEFAULT now(),
  tenant_id    uuid NOT NULL,
  version      int NOT NULL DEFAULT 1       -- optimistic concurrency
);

-- İndeksler (sık aranan kolonlar)
CREATE INDEX musteri_sikayeti_musteri_idx ON musteri_sikayeti(musteri_id);
CREATE INDEX musteri_sikayeti_atanan_idx  ON musteri_sikayeti(atanan_id);
CREATE INDEX musteri_sikayeti_tenant_idx  ON musteri_sikayeti(tenant_id, created_at DESC);

